mapper.update:
UPDATE sched_instance
SET run_status = #{toStatus,jdbcType=TINYINT},
    version = version+1
WHERE instance_id = #{instanceId,jdbcType=BIGINT}
  AND run_status = #{fromStatus,jdbcType=TINYINT}

UPDATE sched_instance
SET is_retrying = #{retrying,javaType=boolean,jdbcType=TINYINT},
    run_status = #{toStatus,jdbcType=TINYINT},
    version = version+1
WHERE instance_id = #{instanceId,jdbcType=BIGINT}
  AND is_retrying = !#{retrying,javaType=boolean,jdbcType=TINYINT}
  AND run_status = #{fromStatus,jdbcType=TINYINT}

mapper.select:
SELECT 
FROM sched_instance
WHERE run_status = #{runStatus,jdbcType=TINYINT}
  AND trigger_time < #{expireTime.time,jdbcType=BIGINT}
  AND next_scan_time < #{expireTime,jdbcType=TIMESTAMP}
  AND (wnstance_id IS NULL OR instance_id != wnstance_id)
ORDER BY trigger_time
LIMIT #{size}

mapper.update:
